HTML = """
<!doctype html><html lang="nl"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1, viewport-fit=cover"><title>Minyad Mobile</title><style>__CSS__</style></head>
<body><main class="app"><header class="top"><div class="brand"><div><h1>Minyad</h1><div class="sub">Mobiel dashboard</div></div><div class="status"><i id="live-dot" class="dot"></i><span id="updated">laden…</span></div></div></header>
<section id="dashboard" class="panel active"><div class="hero"><article class="card summary"><div><div class="label">Zonne-opbrengst nu</div><div class="value solar"><span id="solar">--</span> <small>kW</small></div></div><span id="solar-pill" class="pill">stand-by</span></article></div><div class="tiles"><article class="card tile"><div><div class="label">Batterij</div><div class="value battery"><span id="battery">--</span><small> kW</small></div></div><div><div class="bar split battery"><i id="battery-bar" class="fill"></i></div><div class="meta"><span>laden</span><span>ontladen</span></div></div></article><article class="card tile"><div><div class="label">SoC</div><div class="value battery"><span id="soc">--</span><small>%</small></div></div><div><div class="bar battery"><i id="soc-bar" class="fill"></i></div><div class="meta"><span id="soh">SoH --%</span><span>10 kWh</span></div></div></article><article class="card tile wide"><div><div class="label">Net</div><div id="grid-value" class="value grid"><span id="grid">--</span><small> kW</small></div></div><div><div id="grid-bar-shell" class="bar split grid"><i id="grid-bar" class="fill"></i></div><div class="meta"><span>import</span><span>export</span></div></div></article></div><p id="error" class="error"></p></section>
<section id="flows" class="panel"><article class="card flow"><div class="label">Dashboard flows</div><div class="flow-row solar"><span>Solar</span><div class="rail"><i id="flow-solar"></i></div><b id="flow-solar-v">--</b></div><div class="flow-row battery"><span>Batterij</span><div class="rail"><i id="flow-battery"></i></div><b id="flow-battery-v">--</b></div><div class="flow-row grid"><span>Net</span><div class="rail"><i id="flow-grid"></i></div><b id="flow-grid-v">--</b></div><div class="flow-row blue"><span>Huis</span><div class="rail"><i id="flow-home"></i></div><b id="flow-home-v">--</b></div></article></section>
<section id="details" class="panel"><article class="card flow"><div class="label">Details</div><div class="meta"><span>Batterijstatus</span><b id="battery-state">--</b></div><div class="meta"><span>Bridge</span><b id="bridge">--</b></div><div class="meta"><span>Netstatus</span><b id="grid-state">--</b></div><div class="meta"><span>Zelfvoorziening</span><b id="self">--%</b></div></article></section>
</main><nav class="bottom-nav" aria-label="Mobiele navigatie"><button class="tab active" onclick="showPanel('dashboard',this)">Vandaag</button><button class="tab" onclick="showPanel('flows',this)">Flows</button><button class="tab" onclick="showPanel('details',this)">Details</button><button class="tab" onclick="location.href='/'">Refresh</button></nav>
<script>
const $=id=>document.getElementById(id); const num=v=>{const x=Number(v);return Number.isFinite(x)?x:null}; const fmt=v=>v==null?'--':Math.abs(v).toFixed(2); const signed=v=>v==null?'--':(v>=0?'+':'−')+Math.abs(v).toFixed(2);
function showPanel(id,btn){document.querySelectorAll('.panel').forEach(p=>p.classList.toggle('active',p.id===id));document.querySelectorAll('.tab').forEach(t=>t.classList.remove('active'));btn.classList.add('active')}
function splitBar(id,v,max){const el=$(id); const pct=Math.min(50,Math.abs(v)/max*50); if(v<0){el.style.left=(50-pct)+'%';el.style.width=pct+'%'}else{el.style.left='50%';el.style.width=pct+'%'}}
function rail(id,v,max){$(id).style.width=Math.min(100,Math.abs(v)/max*100)+'%'}
async function update(){try{const [g,b]=await Promise.all([fetch('/api/grid/status').then(r=>r.json()),fetch('/api/battery/status').then(r=>r.json())]); const solar=(num(g.solar_power_w)??0)/1000; const bat=(num(b.power_w)??0)/1000; const grid=-(num(g.grid_net_power_w)??0)/1000; const soc=num(b.soc)??0; const soh=num(b.soh)??0; const home=Math.max(0,solar+bat-grid); $('solar').textContent=fmt(solar); $('battery').textContent=signed(bat); $('grid').textContent=signed(grid); $('soc').textContent=Math.round(soc); $('soh').textContent='SoH '+Math.round(soh)+'%'; $('solar-pill').textContent=solar>.05?'produceert':'stand-by'; $('soc-bar').style.width=Math.max(0,Math.min(100,soc))+'%'; splitBar('battery-bar',bat,3); splitBar('grid-bar',grid,3); const exportMode=grid>=0; $('grid-value').className='value '+(exportMode?'solar':'grid'); $('grid-bar-shell').className='bar split '+(exportMode?'solar':'grid'); $('flow-solar-v').textContent=fmt(solar)+' kW'; $('flow-battery-v').textContent=signed(bat)+' kW'; $('flow-grid-v').textContent=signed(grid)+' kW'; $('flow-home-v').textContent=fmt(home)+' kW'; rail('flow-solar',solar,5); rail('flow-battery',bat,3); rail('flow-grid',grid,3); rail('flow-home',home,6); $('battery-state').textContent=b.state||b.mode_label||'--'; $('bridge').textContent=b.bridge_status||'--'; $('grid-state').textContent=g.grid_status||'--'; const imported=Math.max(0,-grid), used=Math.max(0,solar-Math.max(0,grid)); $('self').textContent=Math.round(100*used/(used+imported||1))+'%'; $('updated').textContent=new Date().toLocaleTimeString([], {hour:'2-digit',minute:'2-digit'}); $('live-dot').className='dot ok'; $('error').textContent='';}catch(e){$('live-dot').className='dot'; $('error').textContent='Kan dashboarddata niet laden: '+(e.message||e);}}
update(); setInterval(update,5000);
</script></body></html>
""".replace("__CSS__", CSS)


@app.api_route("/api/{path:path}", methods=["GET", "POST", "PUT", "DELETE"])
async def api_proxy(path: str, request: Request) -> Response:
    headers = {k: v for k, v in request.headers.items() if k.lower() not in {"host", "content-length"}}
    try:
        async with httpx.AsyncClient(base_url=API_BASE_URL, timeout=10.0) as client:
            response = await client.request(request.method, f"/{path}", params=request.query_params, content=await request.body(), headers=headers)
    except httpx.RequestError as exc:
        return JSONResponse(status_code=502, content={"detail": "Unable to reach Minyad API service", "api_base_url": API_BASE_URL, "error": str(exc)})
    excluded = {"content-encoding", "content-length", "transfer-encoding", "connection"}
    return Response(content=response.content, status_code=response.status_code, headers={k: v for k, v in response.headers.items() if k.lower() not in excluded}, media_type=response.headers.get("content-type"))


@app.get("/", response_class=HTMLResponse)
async def mobile_dashboard() -> str:
    return HTML
